	variant?: string;
	weight?: IconWeightType;
};

export type DBIconProps = DBIconDefaultProps &
	GlobalProps &
	IconProps &
	TextProps;

export type DBIconDefaultState = {};

export type DBIconState = DBIconDefaultState & GlobalState;

