import {
  Component,
  viewChild,
  ElementRef,
  effect,
  AfterViewInit,
} from "@angular/core";
import { CommonModule } from "@angular/common";

import { DBNavigationItem } from "../navigation-item";
import { NavigationContentDirective } from "../NavigationContent.directive";

@Component({
  selector: "navigation-item-active",
  standalone: true,
  imports: [
					NavigationContentDirective,CommonModule, DBNavigationItem],
  template: `<ng-container
    ><ul>
      <db-navigation-item [active]="false"
        ><a href="#" *dbNavigationContent>(Default) False</a></db-navigation-item
      >
    </ul>
    <ul>
      <db-navigation-item [active]="true"
        ><a href="#" *dbNavigationContent>True</a></db-navigation-item
      >
    </ul></ng-container
  > `,
  styles: `:host { display: contents; }`,
})
export class NavigationItemActive implements AfterViewInit {
  _ref = viewChild<ElementRef>("_ref");

  constructor() {}

  /**
   * Passes `aria-*`, `data-*` & `class` attributes to correct child. Used in angular and stencil.
   * @param element  the ref for the component
   * @param customElementSelector  the custom element like `my-component`
   */
  private enableAttributePassing(
    element: HTMLElement | null,
    customElementSelector: string
  ) {
    const parent = element?.closest(customElementSelector);
    if (element && parent) {
      const attributes = parent.attributes;
      for (let i = 0; i < attributes.length; i++) {
        const attr = attributes.item(i);
        if (
          attr && attr.name !== 'data-density' &&
          (attr.name.startsWith("data-") || attr.name.startsWith("aria-"))
        ) {
          element.setAttribute(attr.name, attr.value);
          parent.removeAttribute(attr.name);
        }
        else if (attr  && attr.name !== 'data-density' && attr.name !== "class" && attr.name === "style") {
				element.setAttribute(attr.name, attr.value);
			parent.removeAttribute(attr.name);
		}
					else if (attr && attr.name === "class") {
          const isWebComponent = attr.value.includes("hydrated");
          const value = attr.value.replace("hydrated", "").trim();
          const currentClass = element.getAttribute("class");
          element.setAttribute(
            attr.name,
            `${currentClass ? `${currentClass} ` : ""}${value}`
          );
          if (isWebComponent) {
            // Stencil is using this class for lazy loading component
            parent.setAttribute("class", "hydrated");
          } else {
            parent.removeAttribute(attr.name);
          }
        }
      }
    }
  }

  ngAfterViewInit() {
    if (typeof window !== "undefined") {
      const element: HTMLElement | null = this._ref()?.nativeElement;
      this.enableAttributePassing(element, "navigation-item-active");
    }
  }
}

